{
  "title": "संदर्भ बजट",
  "group": "टोकन प्रबंधन",
  "options": [
    {
      "text": "सूचना को अधिकतम करने के लिए संदर्भ विंडो का 95%+ उपयोग करें"
    },
    {
      "text": "पूरी विंडो भरने के बजाय आउटपुट के लिए पर्याप्त हेडरूम रखें"
    },
    {
      "text": "संदर्भ बजट केवल 32K टोकन से कम मॉडल्स के लिए महत्वपूर्ण है"
    },
    {
      "text": "जब विंडो से अधिक हो जाता है तो मॉडल स्वचालित रूप से ट्रंकेट करता है"
    }
  ],
  "questionProse": [
    "जब पुनः प्राप्त संदर्भ के साथ RAG प्रॉम्प्ट बनाते हैं, तो संदर्भ बजट के लिए एक अच्छा नियम‑अनुमान है:"
  ],
  "explanationProse": [
    "संदर्भ विंडो **इनपुट और आउटपुट** के बीच साझा होती है। यदि आप इनपुट के लिए 90% उपयोग करते हैं, तो मॉडल के पास प्रतिक्रिया उत्पन्न करने के लिए केवल विंडो का 10% बचता है — जिससे अक्सर ट्रंकेटेड या घटे हुए आउटपुट होते हैं।\n\nएक उचित अनुमान: पहले अपने अपेक्षित आउटपुट आकार का निर्णय लें, फिर अपना इनपुट शेष बजट से आराम से नीचे रखें। कई RAG कार्यों के लिए, इसका मतलब है **कुल संदर्भ विंडो के 60–70% से अधिक नहीं** इनपुट के लिए उपयोग करना (सिस्टम प्रॉम्प्ट + इतिहास + पुनः प्राप्त संदर्भ)। शेष भाग को जनरेशन और सुरक्षा मार्जिन के लिए रखें।\n\nइसके अतिरिक्त, मॉडल अपने संदर्भ विंडो के किनारों के पास कम प्रदर्शन करते हैं — जैसे-जैसे संदर्भ भरता है, समझ और निर्देश‑अनुकरण घटते हैं। 95% पर चलाना तकनीकी रूप से संभव है। लेकिन यह 50% पर चलाने के समान अनुभव नहीं है।"
  ]
}
